import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act } from '@testing-library/react';
import { AppProvider, useApp } from '../src/context/AppContext';

// Mock localStorage
const localStorageMock = (() => {
  let store: Record<string, string> = {};
  return {
    getItem: (key: string) => store[key] || null,
    setItem: (key: string, value: string) => { store[key] = value; },
    removeItem: (key: string) => { delete store[key]; },
    clear: () => { store = {}; }
  };
})();

Object.defineProperty(window, 'localStorage', { value: localStorageMock });

describe('AppContext', () => {
  beforeEach(() => {
    localStorageMock.clear();
    vi.clearAllMocks();
  });

  describe('useApp hook', () => {
    it('provides default values', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      expect(result.current.view).toBe('onboarding');
      expect(result.current.user).toBe(null);
      expect(result.current.currentDevotion).toBe(null);
      expect(result.current.isLoading).toBe(false);
      expect(result.current.isDarkMode).toBe(false);
    });

    it('updates view when setView is called', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      act(() => {
        result.current.setView('today');
      });

      expect(result.current.view).toBe('today');
    });

    it('updates selectedNeed when setSelectedNeed is called', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      act(() => {
        result.current.setSelectedNeed('Comfort');
      });

      expect(result.current.selectedNeed).toBe('Comfort');
    });

    it('toggles dark mode', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      expect(result.current.isDarkMode).toBe(false);

      act(() => {
        result.current.toggleDarkMode();
      });

      expect(result.current.isDarkMode).toBe(true);
    });
  });

  describe('User profile', () => {
    it('sets user profile to localStorage', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      const testUser = {
        name: 'Test User',
        faithBackground: 'Curious' as const,
        lifeStages: ['Career'],
        struggles: ['Anxiety'],
        location: 'NYC',
        notificationTime: '07:30'
      };

      act(() => {
        result.current.setUser(testUser);
      });

      expect(result.current.user).toEqual(testUser);
      expect(localStorageMock.getItem('stillness_user')).toBe(JSON.stringify(testUser));
    });

    it('loads user from localStorage on mount', () => {
      const savedUser = {
        name: 'Saved User',
        faithBackground: 'Mature believer' as const,
        lifeStages: ['Retirement'],
        struggles: [],
        location: 'LA',
        notificationTime: '08:00'
      };
      localStorageMock.setItem('stillness_user', JSON.stringify(savedUser));

      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      // After render, user should be loaded and view should be 'today'
      expect(result.current.user?.name).toBe('Saved User');
      expect(result.current.view).toBe('today');
    });
  });

  describe('Devotion state', () => {
    it('sets current devotion', () => {
      const { result } = renderHook(() => useApp(), {
        wrapper: AppProvider
      });

      const testDevotion = {
        id: 'test-1',
        date: '2024-01-01',
        scriptureReference: 'John 3:16',
        scriptureExcerpt: 'For God so loved the world...',
        scriptureContext: 'Jesus speaking to Nicodemus',
        reflection: 'A test reflection',
        stillnessQuestions: ['Question 1'],
        how: ['Do something'],
        prayer: 'Dear God, amen'
      };

      act(() => {
        result.current.setCurrentDevotion(testDevotion);
      });

      expect(result.current.currentDevotion).toEqual(testDevotion);
    });
  });
});

