/**
 * Storage abstraction layer for Stillness app.
 * Uses Capacitor Preferences on native platforms, localStorage as fallback for web.
 */
import { Preferences } from '@capacitor/preferences';

const isNative = () => {
  return typeof window !== 'undefined' &&
    (window as unknown as { Capacitor?: { isNativePlatform?: () => boolean } }).Capacitor?.isNativePlatform?.();
};

// Fallback localStorage for web/development
const webStorage = {
  getItem: (key: string): string | null => {
    try {
      return localStorage.getItem(key);
    } catch {
      return null;
    }
  },
  setItem: (key: string, value: string): void => {
    try {
      localStorage.setItem(key, value);
    } catch {
      // Ignore storage errors
    }
  },
  removeItem: (key: string): void => {
    try {
      localStorage.removeItem(key);
    } catch {
      // Ignore storage errors
    }
  }
};

export const storage = {
  async get(key: string): Promise<string | null> {
    if (isNative()) {
      const { value } = await Preferences.get({ key });
      return value;
    }
    return webStorage.getItem(key);
  },

  async set(key: string, value: string): Promise<void> {
    if (isNative()) {
      await Preferences.set({ key, value });
    } else {
      webStorage.setItem(key, value);
    }
  },

  async remove(key: string): Promise<void> {
    if (isNative()) {
      await Preferences.remove({ key });
    } else {
      webStorage.removeItem(key);
    }
  }
};

// Storage keys used by the app
export const STORAGE_KEYS = {
  USER: 'stillness_user',
  VAULT: 'stillness_vault',
  THEME: 'stillness_theme',
  VERSE_HISTORY: 'stillness_verse_history',
  TODAY_STRUGGLE: 'stillness_today_struggle'
} as const;

/* eslint-disable react-refresh/only-export-components */
import React, { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import type { FaithBackground, UserProfile, Devotion, AppView, DailyNeed } from '@shared/types';
import { storage, STORAGE_KEYS } from '../lib/storage';

interface AppContextType {
  view: AppView;
  setView: (view: AppView) => void;
  devotionOrigin: AppView;
  setDevotionOrigin: (view: AppView) => void;
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  currentDevotion: Devotion | null;
  setCurrentDevotion: (devotion: Devotion | null) => void;
  selectedNeed: DailyNeed;
  setSelectedNeed: (need: DailyNeed) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

function normalizeFaithBackground(value: unknown): FaithBackground {
  if (value === 'Curious' || value === 'Skeptical' || value === 'New Christian' || value === 'Returning' || value === 'Mature believer') {
    return value;
  }

  if (value === 'New believer') return 'New Christian';
  if (value === 'Growing') return 'Returning';
  if (value === 'Mature') return 'Mature believer';

  return 'Curious';
}

function normalizeUserProfile(raw: unknown): UserProfile | null {
  if (!raw || typeof raw !== 'object') return null;
  const data = raw as Partial<UserProfile> & Record<string, unknown>;
  if (!data.name || !data.location) return null;

  return {
    name: String(data.name),
    location: String(data.location),
    grewUpLocation: typeof data.grewUpLocation === 'string' ? data.grewUpLocation : '',
    faithBackground: normalizeFaithBackground(data.faithBackground),
    lifeStages: Array.isArray(data.lifeStages) ? (data.lifeStages as string[]) : [],
    struggles: Array.isArray(data.struggles) ? (data.struggles as string[]) : [],
    notificationTime: typeof data.notificationTime === 'string' ? data.notificationTime : '07:30',
    reminderEnabled: typeof data.reminderEnabled === 'boolean' ? data.reminderEnabled : false
  };
}

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [view, setView] = useState<AppView>('onboarding');
  const [devotionOrigin, setDevotionOrigin] = useState<AppView>('today');
  const [user, setUser] = useState<UserProfile | null>(null);
  const [currentDevotion, setCurrentDevotion] = useState<Devotion | null>(null);
  const [selectedNeed, setSelectedNeed] = useState<DailyNeed>('Hope');
  const [isLoading, setIsLoading] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [storageReady, setStorageReady] = useState(false);

  // Initialize theme from storage (async)
  useEffect(() => {
    const initTheme = async () => {
      try {
        const saved = await storage.get(STORAGE_KEYS.THEME);
        setIsDarkMode(saved === 'dark');
      } catch {
        // Fall back to localStorage for web
        const saved = localStorage.getItem(STORAGE_KEYS.THEME);
        setIsDarkMode(saved === 'dark');
      }
      setStorageReady(true);
    };
    initTheme();
  }, []);

  // Apply dark mode class to document
  useEffect(() => {
    if (!storageReady) return;

    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.documentElement.classList.remove('light');
    } else {
      document.documentElement.classList.add('light');
      document.documentElement.classList.remove('dark');
    }

    // Save to both Capacitor Preferences and localStorage as backup
    storage.set(STORAGE_KEYS.THEME, isDarkMode ? 'dark' : 'light').catch(() => {
      localStorage.setItem(STORAGE_KEYS.THEME, isDarkMode ? 'dark' : 'light');
    });
  }, [isDarkMode, storageReady]);

  // Load user from storage
  useEffect(() => {
    if (!storageReady) return;

    const loadUser = async () => {
      try {
        const savedUser = await storage.get(STORAGE_KEYS.USER);
        if (savedUser) {
          const parsed = JSON.parse(savedUser);
          const normalized = normalizeUserProfile(parsed);
          if (normalized) {
            setUser(normalized);
            setView('today');
            return;
          }
        }
      } catch {
        // Fall back to localStorage
        const savedUser = localStorage.getItem(STORAGE_KEYS.USER);
        if (savedUser) {
          try {
            const parsed = JSON.parse(savedUser);
            const normalized = normalizeUserProfile(parsed);
            if (normalized) {
              setUser(normalized);
              setView('today');
            }
          } catch {
            localStorage.removeItem(STORAGE_KEYS.USER);
          }
        }
      }
    };

    loadUser();
  }, [storageReady]);

  const handleSetUser = useCallback(async (profile: UserProfile | null) => {
    if (profile) {
      const profileJson = JSON.stringify(profile);
      await storage.set(STORAGE_KEYS.USER, profileJson).catch(() => {
        localStorage.setItem(STORAGE_KEYS.USER, profileJson);
      });
    } else {
      await storage.remove(STORAGE_KEYS.USER).catch(() => {
        localStorage.removeItem(STORAGE_KEYS.USER);
      });
    }
    setUser(profile);
  }, []);

  const toggleDarkMode = useCallback(() => {
    setIsDarkMode(prev => !prev);
  }, []);

  return (
    <AppContext.Provider value={{
      view, setView,
      devotionOrigin, setDevotionOrigin,
      user, setUser: handleSetUser,
      currentDevotion, setCurrentDevotion,
      selectedNeed, setSelectedNeed,
      isLoading, setIsLoading,
      isDarkMode, toggleDarkMode
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

/**
 * Local Notifications service for Stillness daily reminders
 */
import { LocalNotifications } from '@capacitor/local-notifications';
import { App } from '@capacitor/app';

export interface ReminderConfig {
  time: string; // HH:mm format
  enabled: boolean;
}

const REMINDER_ID = 'stillness-daily-reminder';

export const notifications = {
  /**
   * Check if notifications permission is granted
   */
  async checkPermission(): Promise<boolean> {
    const result = await LocalNotifications.checkPermissions();
    return result.grants !== undefined && Object.keys(result.grants).length > 0;
  },

  /**
   * Request notification permission
   */
  async requestPermission(): Promise<boolean> {
    const result = await LocalNotifications.requestPermissions();
    return result.grants !== undefined && Object.keys(result.grants).length > 0;
  },

  /**
   * Schedule daily reminder at specified time
   */
  async scheduleReminder(time: string): Promise<boolean> {
    // First cancel any existing reminder
    await this.cancelReminder();

    // Parse time (HH:mm)
    const [hours, minutes] = time.split(':').map(Number);

    try {
      await LocalNotifications.schedule({
        notifications: [
          {
            id: 1,
            title: 'Stillness',
            body: 'Take a moment for your daily devotion',
            schedule: {
              at: new Date(Date.now() + 60000), // Schedule 1 minute from now for immediate effect
              repeats: true,
              every: 'day',
              allowWhileIdle: true
            },
            sound: 'default',
            actionTypeId: REMINDER_ID
          }
        ]
      });

      // Store the reminder time in preferences
      const { Preferences } = await import('@capacitor/preferences');
      await Preferences.set({
        key: 'stillness_reminder_config',
        value: JSON.stringify({ time, enabled: true })
      });

      return true;
    } catch (error) {
      console.error('Failed to schedule notification:', error);
      return false;
    }
  },

  /**
   * Cancel all scheduled reminders
   */
  async cancelReminder(): Promise<void> {
    try {
      await LocalNotifications.cancel({ notifications: [{ id: 1 }] });
    } catch {
      // Ignore errors
    }
  },

  /**
   * Get current reminder config
   */
  async getReminderConfig(): Promise<ReminderConfig | null> {
    try {
      const { Preferences } = await import('@capacitor/preferences');
      const { value } = await Preferences.get({ key: 'stillness_reminder_config' });
      if (value) {
        return JSON.parse(value);
      }
    } catch {
      // Ignore errors
    }
    return null;
  },

  /**
   * Handle notification tap - brings app to foreground
   */
  async handleNotificationTap(): Promise<void> {
    try {
      await LocalNotifications.addListener('localNotificationActionPerformed', (event) => {
        // Bring app to foreground when notification is tapped
        App.focus();
      });
    } catch {
      // Ignore if already registered
    }
  }
};

export default notifications;

/**
 * Local Notifications service for Stillness daily reminders
 */
import { LocalNotifications } from '@capacitor/local-notifications';
import { App } from '@capacitor/app';

export interface ReminderConfig {
  time: string; // HH:mm format
  enabled: boolean;
}

const REMINDER_ID = 'stillness-daily-reminder';

export const notifications = {
  /**
   * Check if notifications permission is granted
   */
  async checkPermission(): Promise<boolean> {
    try {
      const result = await LocalNotifications.checkPermissions();
      return result.display === 'granted';
    } catch {
      return false;
    }
  },

  /**
   * Request notification permission
   */
  async requestPermission(): Promise<boolean> {
    try {
      const result = await LocalNotifications.requestPermissions();
      return result.display === 'granted';
    } catch {
      return false;
    }
  },

  /**
   * Schedule daily reminder at specified time
   */
  async scheduleReminder(time: string): Promise<boolean> {
    // First cancel any existing reminder
    await this.cancelReminder();

    // Parse time (HH:mm)
    const [hours, minutes] = time.split(':').map(Number);

    // Create a date for today at the specified time
    const scheduleDate = new Date();
    scheduleDate.setHours(hours, minutes, 0, 0);

    // If the time has passed today, schedule for tomorrow
    if (scheduleDate.getTime() <= Date.now()) {
      scheduleDate.setDate(scheduleDate.getDate() + 1);
    }

    try {
      await LocalNotifications.schedule({
        notifications: [
          {
            id: 1,
            title: 'Stillness',
            body: 'Take a moment for your daily devotion',
            schedule: {
              at: scheduleDate,
              repeats: true,
              allowWhileIdle: true
            },
            sound: 'default',
            actionTypeId: REMINDER_ID
          }
        ]
      });

      // Store the reminder time in preferences
      const { Preferences } = await import('@capacitor/preferences');
      await Preferences.set({
        key: 'stillness_reminder_config',
        value: JSON.stringify({ time, enabled: true })
      });

      return true;
    } catch (error) {
      console.error('Failed to schedule notification:', error);
      return false;
    }
  },

  /**
   * Cancel all scheduled reminders
   */
  async cancelReminder(): Promise<void> {
    try {
      await LocalNotifications.cancel({ notifications: [{ id: 1 }] });
