      // Ignore errors
    }
  },

  /**
   * Get current reminder config
   */
  async getReminderConfig(): Promise<ReminderConfig | null> {
    try {
      const { Preferences } = await import('@capacitor/preferences');
      const { value } = await Preferences.get({ key: 'stillness_reminder_config' });
      if (value) {
        return JSON.parse(value);
      }
    } catch {
      // Ignore errors
    }
    return null;
  },

  /**
   * Handle notification tap - brings app to foreground
   */
  async handleNotificationTap(): Promise<void> {
    try {
      await LocalNotifications.addListener('localNotificationActionPerformed', () => {
        // Bring app to foreground when notification is tapped
        App.focus();
      });
    } catch {
      // Ignore if already registered
    }
  }
};

