import type { UserProfile, DailyNeed, Devotion } from '@shared/types';
import { storage, STORAGE_KEYS } from '../lib/storage';

const API_BASE = import.meta.env.VITE_API_BASE || '';

type VerseHistoryEntry = {
  reference: string;
  date: string; // ISO
};

async function readVerseHistory(): Promise<VerseHistoryEntry[]> {
  try {
    const raw = await storage.get(STORAGE_KEYS.VERSE_HISTORY);
    if (!raw) return [];
    const parsed = JSON.parse(raw) as VerseHistoryEntry[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    // Fallback to localStorage for web
    const raw = localStorage.getItem(STORAGE_KEYS.VERSE_HISTORY);
    if (!raw) return [];
    try {
      const parsed = JSON.parse(raw) as VerseHistoryEntry[];
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }
}

async function writeVerseHistory(entries: VerseHistoryEntry[]) {
  const data = JSON.stringify(entries.slice(0, 200));
  try {
    await storage.set(STORAGE_KEYS.VERSE_HISTORY, data);
  } catch {
    // Fallback to localStorage for web
    localStorage.setItem(STORAGE_KEYS.VERSE_HISTORY, data);
  }
}

export function getAvoidScriptureReferences(windowDays = 30): Promise<string[]> {
  return readVerseHistory().then(history => {
    const cutoff = Date.now() - windowDays * 24 * 60 * 60 * 1000;
    const recent = history.filter((entry) => {
      const t = Date.parse(entry.date);
      return Number.isFinite(t) && t >= cutoff && typeof entry.reference === 'string' && entry.reference.trim().length > 0;
    });

    const seen = new Set<string>();
    const avoid: string[] = [];
    for (const entry of recent) {
      const ref = entry.reference.trim();
      if (!seen.has(ref)) {
        seen.add(ref);
        avoid.push(ref);
      }
    }
    return avoid;
  });
}

export async function recordScriptureReference(reference: string) {
  const ref = (reference || '').trim();
  if (!ref) return;
  const history = await readVerseHistory();
  await writeVerseHistory([{ reference: ref, date: new Date().toISOString() }, ...history]);
}

async function postJson<T>(path: string, body: unknown, signal?: AbortSignal): Promise<T> {
  const response = await fetch(`${API_BASE}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
    signal
  });

  if (!response.ok) {
    throw new Error(`Request failed: ${response.status}`);
  }

  return response.json() as Promise<T>;
}

export async function generateDailyDevotion(
  user: UserProfile,
  todayNeed: DailyNeed,
  customContext?: string,
  signal?: AbortSignal
): Promise<Devotion> {
  const avoidRefs = await getAvoidScriptureReferences(30);

  const payload = {
    user: {
      name: user.name,
      location: user.location,
      grewUpLocation: user.grewUpLocation,
      struggles: user.struggles,
      lifeStages: user.lifeStages,
      faithBackground: user.faithBackground,
      notificationTime: user.notificationTime,
      reminderEnabled: user.reminderEnabled
    },
    need: todayNeed,
    customContext,
    avoidScriptureReferences: avoidRefs
  };

  return postJson<Devotion>('/api/devotion', payload, signal);
}

export async function getCitySuggestions(input: string): Promise<string[]> {
  if (!input || input.length < 2) return [];
  return postJson<string[]>('/api/city-suggestions', { input });
}

export async function getCityFromCoordinates(latitude: number, longitude: number): Promise<string> {
  const response = await postJson<{ city: string }>('/api/geo-to-city', { latitude, longitude });
  return response.city || '';
}

import React, { useMemo, useState, useEffect } from 'react';
import { Clock, ArrowLeft, Bell, BellOff } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { notifications } from '../lib/notifications';

function formatTime(value: string): string {
  if (!value) return '07:30';
  return value;
}

export default function RitualSetup() {
  const { user, setUser, setView } = useApp();
  const [time, setTime] = useState<string>(user?.notificationTime || '07:30');
  const [enabled, setEnabled] = useState<boolean>(user?.reminderEnabled ?? true);
  const [permissionStatus, setPermissionStatus] = useState<'unknown' | 'granted' | 'denied'>('unknown');
  const [isLoading, setIsLoading] = useState(false);

  const safeTime = useMemo(() => formatTime(time), [time]);

  // Check notification permission on mount
  useEffect(() => {
    const checkPermission = async () => {
      const hasPermission = await notifications.checkPermission();
      setPermissionStatus(hasPermission ? 'granted' : 'denied');
    };
    checkPermission();
  }, []);

  if (!user) return null;

  const handleToggleEnabled = async (newEnabled: boolean) => {
    if (newEnabled && permissionStatus === 'denied') {
      // Request permission when enabling and currently denied
      const granted = await notifications.requestPermission();
      if (!granted) {
        // Permission denied, don't enable
        return;
      }
      setPermissionStatus('granted');
    }

    if (newEnabled && permissionStatus === 'unknown') {
      const granted = await notifications.requestPermission();
      if (!granted) {
        setPermissionStatus('denied');
        return;
      }
      setPermissionStatus('granted');
    }

    setEnabled(newEnabled);
  };

  const save = async () => {
    setIsLoading(true);

    try {
      // Update user profile
      setUser({
        ...user,
        notificationTime: safeTime,
        reminderEnabled: enabled
      });

      // Handle notifications
      if (enabled && permissionStatus === 'granted') {
        await notifications.scheduleReminder(safeTime);
      } else {
        await notifications.cancelReminder();
      }
    } catch (error) {
      console.error('Failed to save reminder settings:', error);
    } finally {
      setIsLoading(false);
      setView('settings');
    }
  };

  return (
    <div className="min-h-screen bg-white px-6 md:px-8 pt-12 pb-20 max-w-xl mx-auto animate-gentle-rise safe-top safe-bottom">
      <header className="relative z-10 flex items-center justify-between mb-12">
        <button
          onClick={() => setView('settings')}
          className="w-12 h-12 rounded-full bg-white border border-slate-100 flex items-center justify-center text-slate-400 hover:text-slate-700 active:scale-95 transition-all"
          aria-label="Back"
        >
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div className="text-center flex-1 -ml-12">
          <p className="label-hero">Ritual</p>
          <h2 className="text-3xl font-serif italic text-slate-900">Daily reminder.</h2>
        </div>
      </header>

      <div className="relative z-10 space-y-10">
        {/* Permission warning */}
        {enabled && permissionStatus === 'denied' && (
          <div className="air-card p-6 border-amber-200 bg-amber-50">
            <div className="flex items-start gap-3">
              <BellOff className="w-5 h-5 text-amber-500 mt-0.5" />
              <div>
                <p className="text-sm font-semibold text-amber-800">Notifications disabled</p>
                <p className="text-xs text-amber-700 mt-1">
                  Enable notifications in your device settings to receive daily reminders.
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="air-card p-10">
          <p className="text-slate-400 font-serif italic leading-relaxed">
            Set a gentle time for stillness. We'll save this preference and use it for device notifications once enabled.
          </p>
        </div>

        <div className="relative flex flex-col items-center justify-center w-full py-4">
          <div className="relative group flex flex-col items-center w-full max-w-[360px]">
            <div className="relative w-full cursor-pointer bg-white border border-slate-100 rounded-[48px] p-10 transition-all duration-700 active:scale-[0.98]" style={{ boxShadow: 'var(--shadow-md)' }}>
              <input
                type="time"
                className="absolute inset-0 opacity-0 cursor-pointer w-full h-full z-20"
                value={safeTime}
                onChange={(e) => setTime(e.target.value)}
              />

              <div className="flex flex-col items-center gap-4">
                <div className="text-slate-300 mb-2">
                  <Clock className="w-6 h-6 strokeWidth={1.5} />
                </div>
                <div className="text-[72px] md:text-[84px] font-serif italic text-slate-900 tracking-tighter leading-none select-none">
                  {safeTime}
                </div>
                <div className="flex flex-col items-center gap-3">
                  <div className="w-12 h-[1px] bg-slate-200 group-hover:w-20 group-hover:bg-slate-400 transition-all duration-1000"></div>
                  <span className="text-[9px] font-bold uppercase tracking-[0.5em] text-slate-300 group-hover:text-slate-500 transition-colors">
                    Adjust Rhythm
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="air-card p-8 flex items-center justify-between gap-6">
          <div className="flex items-center gap-3">
            {enabled && permissionStatus === 'granted' ? (
              <Bell className="w-5 h-5 text-slate-400" />
            ) : (
              <BellOff className="w-5 h-5 text-slate-300" />
            )}
            <div className="space-y-1">
              <div className="text-sm font-semibold text-slate-900">Enable reminders</div>
              <div className="text-xs text-slate-400 font-serif italic">A quiet nudge for your daily devotion.</div>
            </div>
          </div>
          <button
            type="button"
            onClick={() => handleToggleEnabled(!enabled)}
            className={`relative inline-flex h-8 w-14 items-center rounded-full transition-colors duration-300 ${
              enabled ? 'bg-slate-900' : 'bg-slate-200'
            }`}
            aria-pressed={enabled}
          >
            <span
              className={`inline-block h-6 w-6 transform rounded-full bg-white shadow-sm transition-transform duration-300 ${
                enabled ? 'translate-x-7' : 'translate-x-1'
              }`}
            />
          </button>
        </div>

        <button
          onClick={save}
          disabled={isLoading}
          className="w-full btn-primary halo-ring disabled:opacity-50"
        >
          {isLoading ? 'Saving...' : 'Save Ritual'}
        </button>
      </div>
    </div>
  );
}

