      case 'reflection': {
        const isFirstDevotion = vaultItems.length === 0;
        const showReminder = !user?.reminderEnabled;
        return (
          <div className="min-h-screen flex flex-col items-center justify-center p-8 md:p-12 text-center space-y-14 md:space-y-16 animate-gentle-rise safe-top safe-bottom">
