            </div>
            <div className="space-y-4 w-full max-w-sm">
              {showReminder && isFirstDevotion ? (
                <div className="space-y-3">
                  <button
                    onClick={() => setView('ritual')}
                    className="w-full btn-primary halo-ring"
                  >
                    Set daily reminder <Bell className="w-4 h-4 opacity-50" />
                  </button>
                  <p className="text-xs text-slate-400 italic px-4">Make this a daily rhythm. Set a gentle reminder.</p>
                </div>
              ) : showReminder ? (
                <button
                  onClick={() => setView('ritual')}
                  className="text-xs text-slate-400 underline underline-offset-4 hover:text-slate-600 transition-colors"
                >
                  Set a daily reminder
                </button>
              ) : null}
              <button
                onClick={() => setView('today')}
                className="w-full btn-secondary"
              >
                Back to today <ArrowRight className="w-4 h-4 text-slate-300" />
              </button>
            </div>
          </div>
        );
      }
      case 'ritual':
        return <RitualSetup />;
      case 'home':
      case 'discover':
      case 'today':
      case 'explore':
      case 'vault':
      case 'settings':
        return renderTabScreen();
      default:
        return null;
    }
  };

  return (
    <div className="relative min-h-screen">
      {renderView()}
      {user && getTabView(view) ? <TabDock activeTab={getTabView(view)!} onTabChange={(tab) => setView(tab)} /> : null}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <Main />
    </AppProvider>
  );
};

export default App;

