const handleSeal = async () => {
  if (isSealed) return;

  // Use Capacitor storage with localStorage fallback
  const { storage, STORAGE_KEYS } = await import('../lib/storage');

  let existing: string | null;
  let vault: Devotion[] = [];

  try {
    existing = await storage.get(STORAGE_KEYS.VAULT);
    if (existing) {
      vault = JSON.parse(existing);
    }
  } catch {
    // Fallback to localStorage
    existing = localStorage.getItem(STORAGE_KEYS.VAULT);
    if (existing) {
      try {
        vault = JSON.parse(existing);
      } catch {
        vault = [];
      }
    }
  }

  if (!vault.find((d) => d.id === currentDevotion.id)) {
    vault.unshift(currentDevotion);
    const vaultData = JSON.stringify(vault.slice(0, 50));

    try {
      await storage.set(STORAGE_KEYS.VAULT, vaultData);
    } catch {
      // Fallback to localStorage
      localStorage.setItem(STORAGE_KEYS.VAULT, vaultData);
    }
  }

  setIsSealed(true);
  setView('reflection');
};

