// ============================================================================
// SCORING CRITERIA
// ============================================================================

type ScoreCategory = 'theological_faithfulness' | 'relevance_to_profile' | 'gospel_clarity' | 'pastoral_warmth' | 'non_repetition' | 'practical_usefulness';

type EvaluationResult = {
  scenarioId: string;
  scores: Record<ScoreCategory, number>; // 1-5
  output?: Devotion;
  failureReasons: string[];
  notes: string;
};

const SCORE_CRITERIA: Record<ScoreCategory, string> = {
  theological_faithfulness: 'Aligns with Reformed theology, avoids prosperity gospel and mystical language',
  relevance_to_profile: 'Addresses user\'s specific life stage, struggles, location, faith background',
  gospel_clarity: 'Clearly presents Christ, grace, repentance, and hope in redemption',
  pastoral_warmth: 'Tone is compassionate, non-shaming, invites rather than pressures',
  non_repetition: 'Does not repeat recently used scripture references',
  practical_usefulness: 'How questions and practical steps are actionable and specific'
};

// ============================================================================
// EVALUATION ENGINE
// ============================================================================

function evaluateDevotion(devotion: Devotion, scenario: EvaluationScenario): EvaluationResult {
  const failures: string[] = [];

  // 1. Theological faithfulness
  const hasProsperityLanguage = /guaranteed wealth|prosperity|best life now|declare it|speak it into/i.test(devotion.reflection);
  const hasMysticalLanguage = /claim it|decree it|_bind|speak over|prophetic word/i.test(devotion.reflection);
  const hasProperGrace = /grace|faith|repentance|christ|jesus|gospel/i.test(devotion.reflection);

  let theologicalScore = 5;
  if (hasProsperityLanguage) { theologicalScore -= 2; failures.push('Contains prosperity gospel language'); }
  if (hasMysticalLanguage) { theologicalScore -= 2; failures.push('Contains mystical/manifestation language'); }
  if (!hasProperGrace) { theologicalScore -= 2; failures.push('Missing gospel clarity'); }

  // 2. Relevance to profile
  let relevanceScore = 5;
  const userStruggles = scenario.user.struggles.map(s => s.toLowerCase());
  const reflectionLower = devotion.reflection.toLowerCase();

  if (userStruggles.length > 0) {
    const strugglesAddressed = userStruggles.filter(s => reflectionLower.includes(s)).length;
    if (strugglesAddressed === 0) { relevanceScore -= 2; failures.push('Does not address user\'s stated struggles'); }
    else if (strugglesAddressed < userStruggles.length) { relevanceScore -= 1; }
  }

  // Faith background relevance
  if (scenario.user.faithBackground === 'Curious' || scenario.user.faithBackground === 'Skeptical') {
    const hasPressure = /you must|you should believe|make a decision|accept jesus now/i.test(devotion.reflection);
    if (hasPressure) { relevanceScore -= 2; failures.push('Pressuring seeker user'); }
  }

  // 3. Gospel clarity
  let gospelScore = 5;
  const gospelReferences = (devotion.reflection + devotion.prayer).toLowerCase();
  if (!gospelReferences.includes('christ') && !gospelReferences.includes('jesus')) {
    gospelScore -= 3; failures.push('No explicit mention of Christ');
  }
  if (!gospelReferences.includes('grace') && !gospelReferences.includes('faith')) {
    gospelScore -= 2; failures.push('No mention of grace or faith');
  }

  // 4. Pastoral warmth
  let warmthScore = 5;
  const hasShame = /you should be ashamed|you are sinful|your fault|you failed/i.test(devotion.reflection);
  if (hasShame) { warmthScore -= 3; failures.push('Shaming language detected'); }

  // 5. Non-repetition (simplified - just check structure)
  let nonRepScore = 5;
  if (!devotion.scriptureReference || devotion.scriptureReference.length < 3) {
    nonRepScore -= 2; failures.push('Invalid scripture reference');
  }

  // 6. Practical usefulness
  let practicalScore = 5;
  if (!devotion.how || devotion.how.length !== 3) {
    practicalScore -= 2; failures.push('Missing 3 practical steps');
  }
  if (!devotion.stillnessQuestions || devotion.stillnessQuestions.length !== 3) {
    practicalScore -= 2; failures.push('Missing 3 stillness questions');
  }
  const hasActionableHow = devotion.how?.some(h => h.includes('read', 'pray', 'share', 'serve', 'call', 'write', 'fast', 'worship'));
  if (!hasActionableHow) { practicalScore -= 2; failures.push('Practical steps not actionable'); }

  return {
    scenarioId: scenario.id,
    scores: {
      theological_faithfulness: Math.max(1, theologicalScore),
      relevance_to_profile: Math.max(1, relevanceScore),
      gospel_clarity: Math.max(1, gospelScore),
      pastoral_warmth: Math.max(1, warmthScore),
      non_repetition: Math.max(1, nonRepScore),
      practical_usefulness: Math.max(1, practicalScore)
    },
    output: devotion,
    failureReasons: failures,
    notes: failures.length === 0 ? 'PASSED' : `Failed: ${failures.join('; ')}`
  };
}

