export function summarizeResults(results: EvaluationResult[]) {
  const totals: Record<ScoreCategory, number> = {
    theological_faithfulness: 0,
    relevance_to_profile: 0,
    gospel_clarity: 0,
    pastoral_warmth: 0,
    non_repetition: 0,
    practical_usefulness: 0
  };

  let totalFailures = 0;

  for (const result of results) {
    for (const [key, score] of Object.entries(result.scores)) {
      totals[key as ScoreCategory] += score;
    }
    totalFailures += result.failureReasons.length;
  }

  console.log('\n=== EVALUATION SUMMARY ===');
  console.log(`Total scenarios: ${results.length}`);
  console.log(`Total failures: ${totalFailures}`);

  for (const [key, total] of Object.entries(totals)) {
    const avg = total / results.length;
    console.log(`${key}: ${avg.toFixed(2)}/5.0`);
  }

  // Identify common failures
  const allFailures = results.flatMap(r => r.failureReasons);
  const failureCounts = allFailures.reduce((acc, f) => {
    acc[f] = (acc[f] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  console.log('\n=== COMMON FAILURES ===');
  for (const [failure, count] of Object.entries(failureCounts).sort((a, b) => b[1] - a[1])) {
    console.log(`  ${count}x: ${failure}`);
  }
}

