// Stillness Service Worker
const CACHE_NAME = 'stillness-v1';
const OFFLINE_URL = '/offline.html';

// Assets to cache on install
const PRECACHE_ASSETS = [
  '/',
  '/index.html',
  '/manifest.json',
];

// Install event - cache core assets
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(PRECACHE_ASSETS);
    })
  );
  // Activate immediately
  self.skipWaiting();
});

// Activate event - clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames
          .filter((name) => name !== CACHE_NAME)
          .map((name) => caches.delete(name))
      );
    })
  );
  // Take control immediately
  self.clients.claim();
});

// Fetch event - network first, fallback to cache
self.addEventListener('fetch', (event) => {
  const { request } = event;
  const url = new URL(request.url);

  // Skip non-GET requests
  if (request.method !== 'GET') return;

  // Skip API calls - always go to network
  if (url.pathname.startsWith('/api/')) {
    event.respondWith(
      fetch(request).catch(() => {
        return new Response(
          JSON.stringify({ error: 'Offline', message: 'Please check your connection' }),
          {
            status: 503,
            headers: { 'Content-Type': 'application/json' }
          }
        );
      })
    );
    return;
  }

  // For HTML pages - network first
  if (request.headers.get('accept')?.includes('text/html')) {
    event.respondWith(
      fetch(request)
        .then((response) => {
          // Cache successful responses
          if (response.status === 200) {
            const clone = response.clone();
            caches.open(CACHE_NAME).then((cache) => {
              cache.put(request, clone);
            });
          }
          return response;
        })
        .catch(() => {
          // Fallback to cache
          return caches.match(request).then((cached) => {
            return cached || caches.match(OFFLINE_URL);
          });
        })
    );
    return;
  }

  // For other assets - cache first
  event.respondWith(
    caches.match(request).then((cached) => {
      if (cached) return cached;

      return fetch(request).then((response) => {
        if (response.status === 200) {
          const clone = response.clone();
          caches.open(CACHE_NAME).then((cache) => {
            cache.put(request, clone);
          });
        }
        return response;
      });
    })
  );
});

// Handle push notifications (for future use)
self.addEventListener('push', (event) => {
  if (!event.data) return;

  const data = event.data.json();
  const options = {
    body: data.body || 'Time for your daily devotion',
    icon: '/icons/icon-192.png',
    badge: '/icons/icon-72.png',
    data: data.url || '/',
    actions: [
      { action: 'open', title: 'Open Stillness' },
    ]
  };

  event.waitUntil(
    self.registration.showNotification(data.title || 'Stillness', options)
  );
});

// Handle notification clicks
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  if (event.action === 'open' || !event.action) {
    event.waitUntil(
      clients.openWindow(event.notification.data)
    );
  }
});

/**
 * Calendar reminder utility for web app
 * Generates .ics files for adding daily devotion reminders to calendar
 */

/**
 * Generate an ICS file content for daily reminder
 */
export function generateICSContent(
  reminderTime: string, // HH:MM format
  title: string = 'Daily Devotion',
  description: string = 'Time for your daily stillness and reflection.'
): string {
  // Parse the time
  const [hours, minutes] = reminderTime.split(':').map(Number);

  // Get current date and set the reminder time
  const now = new Date();
  const startDate = new Date(now);
  startDate.setHours(hours, minutes, 0, 0);

  // If the time has passed today, start tomorrow
  if (startDate <= now) {
    startDate.setDate(startDate.getDate() + 1);
  }

  // Format date for ICS (YYYYMMDDTHHMMSS)
  const formatICSDate = (date: Date): string => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hour = String(date.getHours()).padStart(2, '0');
    const min = String(date.getMinutes()).padStart(2, '0');
    return `${year}${month}${day}T${hour}${min}00`;
  };

  const dtStart = formatICSDate(startDate);
  const dtEnd = formatICSDate(new Date(startDate.getTime() + 15 * 60 * 1000)); // 15 min duration
  const dtStamp = formatICSDate(now);

  // Generate recurrence rule (daily)
  const rrule = 'RRULE:FREQ=DAILY';

  // Generate UID
  const uid = `stillness-daily-${Date.now()}@stillness.app`;

  const icsContent = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//Stillness//Daily Devotion//EN',
    'CALSCALE:GREGORIAN',
    'METHOD:PUBLISH',
    'BEGIN:VEVENT',
    `UID:${uid}`,
    `DTSTAMP:${dtStamp}`,
    `DTSTART:${dtStart}`,
    `DTEND:${dtEnd}`,
    `SUMMARY:${title}`,
    `DESCRIPTION:${description}`,
    rrule,
    'BEGIN:VALARM',
    'TRIGGER:-PT15M',
    'ACTION:DISPLAY',
    'DESCRIPTION:Reminder: Daily Devotion in 15 minutes',
    'END:VALARM',
    'END:VEVENT',
    'END:VCALENDAR'
  ].join('\r\n');

  return icsContent;
}

/**
 * Trigger download of ICS file
 */
export function downloadCalendarReminder(
  reminderTime: string,
  userName: string
): void {
  const title = `Daily Devotion - ${userName}`;
  const description = `Your daily stillness moment with God. Created by ${userName}.`;

  const icsContent = generateICSContent(reminderTime, title, description);

  // Create blob and download
  const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
  const url = URL.createObjectURL(blob);

  const link = document.createElement('a');
  link.href = url;
  link.download = `stillness-daily-reminder.ics`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);

  URL.revokeObjectURL(url);
}

/**
 * Check if running on iOS Safari
 */
export function isIOSafari(): boolean {
  const ua = navigator.userAgent;
  return /iPhone|iPad|iPod/.test(ua) && /Safari/.test(ua) && !/Chrome/.test(ua);
}

/**
 * Check if already added to home screen (standalone mode)
 */
export function isStandalone(): boolean {
  return window.matchMedia('(display-mode: standalone)').matches ||
    (window.navigator as any).standalone === true;
}

/**
 * Show iPhone install prompt guidance
 */
export function shouldShowInstallPrompt(): boolean {
  // Don't show if already installed
  if (isStandalone()) return false;

  // Check if iOS
  const isIOS = /iPhone|iPad|iPod/.test(navigator.userAgent);
  return isIOS;
}

