type DailyNeed = 'Comfort' | 'Wisdom' | 'Courage' | 'Conviction' | 'Gratitude' | 'Hope' | 'Discovery';

// Extended test scenarios - 35 cases
const SCENARIOS: Array<{ id: string; name: string; user: UserProfile; need: DailyNeed }> = [
