  // Additional 14 cases for edge cases
  { id: 'u1', name: 'Decision uncertainty', user: { name: 'Maya', faithBackground: 'Curious', lifeStages: ['Career'], struggles: ['Confusion', 'Decision'], location: 'NYC', notificationTime: '07:00' }, need: 'Wisdom' },
  { id: 'u2', name: 'Career direction', user: { name: 'James', faithBackground: 'New Christian', lifeStages: ['Career'], struggles: ['Purpose', 'Direction'], location: 'Seattle', notificationTime: '07:30' }, need: 'Discovery' },
  { id: 'p1', name: 'Repentance need', user: { name: 'Rebecca', faithBackground: 'Returning', lifeStages: ['Career'], struggles: ['Repentance', 'Guilt'], location: 'Portland', notificationTime: '08:00' }, need: 'Conviction' },
  { id: 'p2', name: 'Forgiveness struggle', user: { name: 'Michael', faithBackground: 'Mature believer', lifeStages: ['Parent'], struggles: ['Unforgiveness', 'Bitterness'], location: 'Denver', notificationTime: '06:30' }, need: 'Gratitude' },
  { id: 'sd1', name: 'Deep spiritual dryness', user: { name: 'Sarah', faithBackground: 'Mature believer', lifeStages: ['Ministry'], struggles: ['Spiritual dryness', 'Doubt'], location: 'Nashville', notificationTime: '05:30' }, need: 'Hope' },
  { id: 'sd2', name: 'Desert season', user: { name: 'David', faithBackground: 'Returning', lifeStages: ['Mid-career'], struggles: ['Desert', 'Walking away'], location: 'Austin', notificationTime: '07:00' }, need: 'Courage' },
  { id: 'id1', name: 'Identity crisis', user: { name: 'Emma', faithBackground: 'New Christian', lifeStages: ['Student'], struggles: ['Identity', 'Self-worth'], location: 'Boston', notificationTime: '08:00' }, need: 'Discovery' },
  { id: 'id2', name: 'Midlife transition', user: { name: 'Robert', faithBackground: 'Mature believer', lifeStages: ['Empty nester'], struggles: ['Midlife crisis', 'Purpose'], location: 'Phoenix', notificationTime: '06:00' }, need: 'Wisdom' },
  { id: 'ch1', name: 'Church hurt', user: { name: 'Lisa', faithBackground: 'Returning', lifeStages: ['Career'], struggles: ['Church hurt', 'Bitterness'], location: 'Atlanta', notificationTime: '07:30' }, need: 'Comfort' },
  { id: 'ch2', name: 'Leadership pressure', user: { name: 'Daniel', faithBackground: 'Mature believer', lifeStages: ['Leadership'], struggles: ['Pressure', 'Burnout'], location: 'Dallas', notificationTime: '06:00' }, need: 'Courage' },
  { id: 're1', name: 'Relationship conflict', user: { name: 'Amy', faithBackground: 'New Christian', lifeStages: ['Married'], struggles: ['Relationship conflict', 'Anger'], location: 'Miami', notificationTime: '07:00' }, need: 'Wisdom' },
  { id: 're2', name: 'Family tension', user: { name: 'Chris', faithBackground: 'Returning', lifeStages: ['Parent'], struggles: ['Family', 'Forgiveness'], location: 'Chicago', notificationTime: '08:30' }, need: 'Gratitude' },
  { id: 'f1', name: 'Financial stress', user: { name: 'Kevin', faithBackground: 'Curious', lifeStages: ['Early career'], struggles: ['Financial stress', 'Fear'], location: 'SF', notificationTime: '07:30' }, need: 'Comfort' },
  { id: 'f2', name: 'Health crisis', user: { name: 'Nancy', faithBackground: 'Mature believer', lifeStages: ['Retirement'], struggles: ['Health concerns', 'Fear'], location: 'Tampa', notificationTime: '08:00' }, need: 'Hope' },
];

async function callDevotionAPI(user: UserProfile, need: DailyNeed) {
  const res = await fetch(`${API_BASE}/api/devotion`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ user, need, avoidScriptureReferences: [] })
  });
  if (!res.ok) throw new Error(`${res.status} ${res.statusText}`);
  return res.json();
}

function evaluateDevotion(devotion: any, scenario: typeof SCENARIOS[0]) {
  const scores: Record<string, number> = {};
  const weaknesses: string[] = [];

  // 1. Theological faithfulness (1-10)
  let theoScore = 8;
  if (/guaranteed wealth|best life now|declare it|speak it into|pronounce/i.test(devotion.reflection)) {
    theoScore -= 3;
    weaknesses.push('Prosperity gospel');
  }
  if (/claim it|decree it|bind|loose|speak over|prophetic/i.test(devotion.reflection)) {
    theoScore -= 2;
    weaknesses.push('Mystical language');
  }
  if (!/grace|faith|repentance|christ|jesus|gospel/i.test(devotion.reflection.toLowerCase())) {
    theoScore -= 3;
    weaknesses.push('Missing gospel');
  }
  scores.theological_faithfulness = Math.max(1, theoScore);

  // 2. Relevance to profile (1-10)
  let relScore = 8;
  const userStruggles = (scenario.user.struggles || []).map(s => s.toLowerCase());
  if (userStruggles.length > 0) {
    const reflectionLower = devotion.reflection.toLowerCase();
    const strugglesAddressed = userStruggles.filter(s => reflectionLower.includes(s)).length;
    if (strugglesAddressed === 0) {
      relScore -= 4;
      weaknesses.push('Struggles not addressed');
    } else if (strugglesAddressed < userStruggles.length) {
      relScore -= 1;
    }
  }
  // Seekers shouldn't be pressured
  if (scenario.user.faithBackground === 'Curious' || scenario.user.faithBackground === 'Skeptical') {
    if (/you must|you should believe|make a decision|accept jesus now/i.test(devotion.reflection)) {
      relScore -= 3;
      weaknesses.push('Pressuring seeker');
    }
  }
  scores.relevance_to_profile = Math.max(1, relScore);

  // 3. Gospel clarity (1-10)
  let gospelScore = 8;
  const gospelText = (devotion.reflection + devotion.prayer).toLowerCase();
  if (!gospelText.includes('christ') && !gospelText.includes('jesus')) {
    gospelScore -= 4;
    weaknesses.push('No Christ reference');
  }
  if (!gospelText.includes('grace') && !gospelText.includes('faith')) {
    gospelScore -= 2;
    weaknesses.push('No grace/faith');
  }
  scores.gospel_clarity = Math.max(1, gospelScore);

  // 4. Pastoral warmth (1-10)
  let warmScore = 8;
  if (/you should be ashamed|you are sinful|your fault|you failed/i.test(devotion.reflection)) {
    warmScore -= 4;
    weaknesses.push('Shaming language');
  }
  scores.pastoral_warmth = Math.max(1, warmScore);

  // 5. Practical guidance (1-10)
  let pracScore = 7;
  if (!devotion.how || devotion.how.length !== 3) {
    pracScore -= 3;
    weaknesses.push('Missing 3 steps');
  }
  const hasAction = devotion.how?.some((h: string) => /read|pray|share|serve|call|write|fast|worship/i.test(h));
  if (!hasAction) {
    pracScore -= 2;
    weaknesses.push('Steps not actionable');
  }
  scores.practical_guidance = Math.max(1, pracScore);

  // 6. Non-repetition (1-10)
  let repScore = 8;
  if (!devotion.scriptureReference || devotion.scriptureReference.length < 3) {
    repScore -= 3;
    weaknesses.push('Invalid scripture');
  }
  scores.non_repetition = Math.max(1, repScore);

  return { scores, weaknesses };
}

async function main() {
  console.log(`=== EXTENDED DEVOTION QUALITY EVALUATION ===`);
  console.log(`Running ${SCENARIOS.length} live API calls...\n`);

  const results: any[] = [];

  for (const scenario of SCENARIOS) {
    process.stdout.write(`[${scenario.id}] ${scenario.name} (${scenario.need})... `);

    try {
      const devotion = await callDevotionAPI(scenario.user as UserProfile, scenario.need as DailyNeed);
      const evaluation = evaluateDevotion(devotion, scenario);
      const avgScore = Object.values(evaluation.scores).reduce((a, b) => a + b, 0) / 6;

      console.log(`OK (avg: ${avgScore.toFixed(1)}/10)`);

      results.push({
        id: scenario.id,
        name: scenario.name,
