  }

  // Weakest results
  console.log('\n=== WEAKEST RESULTS (first 5) ===');
  const scored = successful
    .map(r => ({ ...r, avg: Object.values(r.scores!).reduce((a, b) => a + b, 0) / 6 }))
    .sort((a, b) => a.avg - b.avg)
    .slice(0, 5);

  for (const r of scored) {
    console.log(`\n[${r.id}] ${r.name} - ${r.need}`);
    console.log(`  Scores: ${JSON.stringify(r.scores)}`);
    console.log(`  Weaknesses: ${(r.weaknesses || []).join('; ')}`);
  }
}

