import 'dotenv/config';
import type { VercelRequest, VercelResponse } from '@vercel/node';
import { randomUUID } from 'node:crypto';
import { LRUCache } from 'lru-cache';
import type { DailyNeed, Devotion, UserProfile } from '../shared/types';
import { getAiProvider } from '../server/providers';
import { buildDevotionPrompts } from '../server/prompts/devotion';
import { suggestCities } from '../server/locationIndex';
import { assessOutput, buildCrisisDevotion, extractSafetySignal } from '../server/guardrails';

const cityCache = new LRUCache<string, string[]>({
  max: 500,
  ttl: 1000 * 60 * 60 * 12
});

const reverseGeoCache = new LRUCache<string, string>({
  max: 500,
  ttl: 1000 * 60 * 60 * 24
});

function normalizeReference(value: string): string {
  return (value || '')
    .toLowerCase()
    .replace(/\(.*?\)/g, ' ')
    .replace(/[^a-z0-9:]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function buildDevotionFromData(data: Partial<Devotion>): Devotion {
  return {
    id: randomUUID(),
    date: new Date().toISOString(),
    scriptureReference: data.scriptureReference || 'Psalm 46:10',
    scriptureExcerpt: data.scriptureExcerpt || 'Be still, and know that I am God.',
    scriptureContext: data.scriptureContext || 'The Psalmist calls the people of God to recognize His sovereignty.',
    reflection: data.reflection || 'Your struggles are seen by the One who holds the stars.',
    stillnessQuestions: Array.isArray(data.stillnessQuestions) ? data.stillnessQuestions : [
      'Where is your heart resting?',
      'What are you afraid to let go of?',
      'Is He enough?'
    ],
    how: Array.isArray(data.how) ? data.how : ['Listen.', 'Reflect.', 'Act.'],
    prayer: data.prayer || 'Father, take this burden from me. Amen.'
  };
}

function parseJsonObject<T>(input: string, fallback: T): T {
  const direct = safeParseJson<T>(input);
  if (direct) return direct;

  const trimmed = input.trim();
  const start = trimmed.indexOf('{');
  const end = trimmed.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    const candidate = trimmed.slice(start, end + 1);
    const parsed = safeParseJson<T>(candidate);
    if (parsed) return parsed;
  }

  return fallback;
}

function safeParseJson<T>(input: string): T | null {
  try {
    return JSON.parse(input) as T;
  } catch {
    return null;
  }
}

async function generateDevotion(
  user: UserProfile,
  need: DailyNeed,
  customContext?: string,
  options?: { avoidScriptureReferences?: string[] }
): Promise<Devotion> {
  const avoidList = (options?.avoidScriptureReferences || []).map(normalizeReference).filter(Boolean);
  const avoidSet = new Set(avoidList);
  const attempts = avoidSet.size > 0 ? 2 : 1;
  let last: Partial<Devotion> = {};

  for (let attempt = 0; attempt < attempts; attempt += 1) {
    const prompts = buildDevotionPrompts(user, need, customContext, {
      avoidScriptureReferences: options?.avoidScriptureReferences,
      attempt
    });

    const provider = getAiProvider();
    const response = await provider.chatCompletion({
      system: prompts.system,
      user: prompts.user,
      temperature: 0.4,
      maxTokens: 1200
    });

    const data = parseJsonObject<Partial<Devotion>>(response, {});
    last = data;

    if (!avoidSet.size) {
      return buildDevotionFromData(data);
    }

    const reference = normalizeReference(data.scriptureReference || '');
    if (reference && !avoidSet.has(reference)) {
      return buildDevotionFromData(data);
    }
  }

  return buildDevotionFromData(last);
}

async function generateCitySuggestions(input: string): Promise<string[]> {
  const key = input.trim().toLowerCase();
  const cached = cityCache.get(key);
  if (cached) return cached;

  const suggestions = suggestCities(input, 5);
  cityCache.set(key, suggestions);
  return suggestions;
}

async function reverseGeocode(latitude: number, longitude: number): Promise<string> {
  const key = `${latitude.toFixed(4)},${longitude.toFixed(4)}`;
  const cached = reverseGeoCache.get(key);
  if (cached) return cached;

  const provider = getAiProvider();
  const response = await provider.chatCompletion({
    system: 'You are a location assistant. Respond with just "City, Country".',
    user: `Based on coordinates ${latitude}, ${longitude}, what is the City and Country? Respond with just "City, Country".`,
    maxTokens: 80
  });

  const city = response.replace(/\s+/g, ' ').trim();
  reverseGeoCache.set(key, city);
  return city;
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  // Enable CORS
  const allowedOrigins = (process.env.CORS_ORIGIN || 'http://localhost:3000,http://localhost:5173,http://localhost:5174,http://localhost:5175,capacitor://localhost,https://stillness-daily-devotion.vercel.app').split(',');

  const origin = req.headers.origin || '';
  if (allowedOrigins.includes(origin) || !origin) {
    res.setHeader('Access-Control-Allow-Origin', origin || '*');
  }
  res.setHeader('Access-Control-Allow-Methods', 'POST, GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') {
    return res.status(200).end();
  }

  try {
    if (req.method === 'POST' && req.path === '/api/devotion') {
      const { user, need, customContext, avoidScriptureReferences } = req.body;

      if (!user || !need) {
        return res.status(400).json({ error: 'Missing user or need.' });
      }

      const safetySignal = extractSafetySignal([
        user.name,
        user.location,
        user.struggles?.join(' '),
        customContext
      ]);

      if (safetySignal.level !== 'none') {
        const safeDevotion = buildCrisisDevotion({ name: user.name });
        return res.json({ ...safeDevotion, safety: safetySignal });
      }

      const devotion = await generateDevotion(user, need, customContext, { avoidScriptureReferences });
      const enrichedDevotion = { ...devotion };

      const outputAssessment = assessOutput({
        scriptureReference: enrichedDevotion.scriptureReference,
        reflection: enrichedDevotion.reflection
      });

      return res.json({ ...enrichedDevotion, safety: outputAssessment });
    }

    if (req.method === 'POST' && req.path === '/api/city-suggestions') {
      const { input } = req.body;
      const suggestions = await generateCitySuggestions(input);
      return res.json(suggestions);
    }

    if (req.method === 'POST' && req.path === '/api/geo-to-city') {
      const { latitude, longitude } = req.body;
      const city = await reverseGeocode(latitude, longitude);
      return res.json({ city });
    }

    return res.status(404).json({ error: 'Not found' });
  } catch (error) {
    console.error('API error:', error);
    return res.status(500).json({ error: error instanceof Error ? error.message : 'Internal server error' });
  }
}

