import 'dotenv/config';
import type { VercelRequest, VercelResponse } from '@vercel/node';
import { randomUUID } from 'node:crypto';
import { LRUCache } from 'lru-cache';
import type { DailyNeed, Devotion, UserProfile } from '../shared/types';

// === AI Provider (inline from server/providers) ===
type ChatMessage = {
  role: 'system' | 'user' | 'assistant';
  content: string;
};

type ChatCompletionRequest = {
  model: string;
  messages: ChatMessage[];
  temperature?: number;
  max_tokens?: number;
  max_completion_tokens?: number;
};

type OpenAICompatibleConfig = {
  provider: string;
  apiKey: string;
  baseUrl: string;
  model: string;
  timeoutMs?: number;
};

type ChatCompletionOptions = {
  system: string;
  user: string;
  temperature?: number;
  maxTokens?: number;
};

type OpenAICompatibleClient = {
  provider: string;
  model: string;
  chatCompletion: (options: ChatCompletionOptions) => Promise<string>;
};

function shouldUseMaxCompletionTokens(provider: string, model: string): boolean {
  if (provider !== 'openai') return false;
  const normalizedModel = model.toLowerCase();
  return normalizedModel.startsWith('gpt-5') || normalizedModel.startsWith('o1') || normalizedModel.startsWith('o3') || normalizedModel.startsWith('o4');
}

function shouldUseDefaultTemperature(provider: string, model: string): boolean {
  if (provider !== 'openai') return false;
  const normalizedModel = model.toLowerCase();
  return normalizedModel.startsWith('gpt-5') || normalizedModel.startsWith('o1') || normalizedModel.startsWith('o3') || normalizedModel.startsWith('o4');
}

function isUnsupportedMaxTokensError(status: number, body: string): boolean {
  if (status !== 400) return false;
  const message = body.toLowerCase();
  return message.includes('unsupported parameter') && message.includes('max_tokens') && message.includes('max_completion_tokens');
}

function isUnsupportedTemperatureValueError(status: number, body: string): boolean {
  if (status !== 400) return false;
  const message = body.toLowerCase();
  return message.includes('unsupported value') && message.includes('temperature') && message.includes('default') && message.includes('1');
}

function isUnsupportedTemperatureParameterError(status: number, body: string): boolean {
  if (status !== 400) return false;
  const message = body.toLowerCase();
  return message.includes('unsupported parameter') && message.includes('temperature');
}

function rewriteCompatibilityPayload(payload: ChatCompletionRequest, status: number, body: string): ChatCompletionRequest | null {
  if (typeof payload.max_tokens === 'number' && isUnsupportedMaxTokensError(status, body)) {
    const rewritten: ChatCompletionRequest = { ...payload, max_completion_tokens: payload.max_tokens };
    delete rewritten.max_tokens;
    return rewritten;
  }
  if (typeof payload.temperature === 'number' && isUnsupportedTemperatureValueError(status, body)) {
    if (payload.temperature === 1) return null;
    return { ...payload, temperature: 1 };
  }
  if (typeof payload.temperature === 'number' && isUnsupportedTemperatureParameterError(status, body)) {
    const rewritten: ChatCompletionRequest = { ...payload };
    delete rewritten.temperature;
    return rewritten;
  }
  return null;
}

function parseContent(data: { choices?: Array<{ text?: string; message?: { content?: string | Array<{ type?: string; text?: string }>; refusal?: string }> }>): string {
  const choice = data.choices?.[0];
  if (!choice) throw new Error('AI provider returned empty response.');
  const refusal = choice.message?.refusal?.trim();
  if (refusal) throw new Error(`AI provider refusal: ${refusal}`);
  const rawContent = choice.message?.content;
  let content = '';
  if (typeof rawContent === 'string') {
    content = rawContent.trim();
  } else if (Array.isArray(rawContent)) {
    content = rawContent.map((part) => (typeof part?.text === 'string' ? part.text : '')).filter(Boolean).join('\n').trim();
  } else if (typeof choice.text === 'string') {
    content = choice.text.trim();
  }
  if (!content) throw new Error('AI provider returned empty response.');
  return content;
}

function isFailoverEligible(error: unknown): boolean {
  if (error instanceof Error) {
    const match = error.message.match(/AI provider error (\d{3}):/);
    if (match) {
      const status = Number(match[1]);
      if (status === 429 || status >= 500) return true;
    }
    const message = error.message.toLowerCase();
    if (message.includes('aborted') || message.includes('timeout') || message.includes('network') || message.includes('fetch failed')) return true;
  }
  return false;
}

function createOpenAICompatibleClient(config: OpenAICompatibleConfig): OpenAICompatibleClient {
  const baseUrl = config.baseUrl.replace(/\/$/, '');
  const timeoutMs = config.timeoutMs ?? 15000;

  const chatCompletion = async ({ system, user, temperature, maxTokens }: ChatCompletionOptions) => {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), timeoutMs);

    try {
      const payload: ChatCompletionRequest = {
        model: config.model,
        messages: [{ role: 'system', content: system }, { role: 'user', content: user }]
      };

      if (typeof temperature === 'number' && !shouldUseDefaultTemperature(config.provider, config.model)) {
        payload.temperature = temperature;
      }
      if (typeof maxTokens === 'number') {
        if (shouldUseMaxCompletionTokens(config.provider, config.model)) {
          payload.max_completion_tokens = maxTokens;
        } else {
          payload.max_tokens = maxTokens;
        }
      }

      const requestCompletion = async (requestPayload: ChatCompletionRequest) => {
        const response = await fetch(`${baseUrl}/chat/completions`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${config.apiKey}`
          },
          body: JSON.stringify(requestPayload),
          signal: controller.signal
        });

        if (!response.ok) {
          const text = await response.text();
          return { ok: false as const, status: response.status, body: text };
        }

        const data = await response.json();
        return { ok: true as const, data };
      };

      let currentPayload = payload;
      for (let attempt = 0; attempt < 3; attempt += 1) {
        const result = await requestCompletion(currentPayload);
        if (result.ok) return parseContent(result.data);

        const rewrittenPayload = rewriteCompatibilityPayload(currentPayload, result.status, result.body);
        if (rewrittenPayload) {
          const nextPayload = JSON.stringify(rewrittenPayload);
          const currentPayloadString = JSON.stringify(currentPayload);
          if (nextPayload !== currentPayloadString) {
            currentPayload = rewrittenPayload;
            continue;
          }
        }
        throw new Error(`AI provider error ${result.status}: ${result.body}`);
      }

      throw new Error('AI provider compatibility retries exhausted.');
    } finally {
      clearTimeout(timeout);
    }
  };

  return { provider: config.provider, model: config.model, chatCompletion };
}

function createFailoverClient(clients: OpenAICompatibleClient[]): OpenAICompatibleClient {
  if (clients.length === 0) throw new Error('No AI clients configured.');
  if (clients.length === 1) return clients[0];

  return {
    provider: clients.map((c) => c.provider).join(' -> '),
    model: clients[0].model,
    chatCompletion: async (options: ChatCompletionOptions) => {
      let lastError: unknown;
      for (let index = 0; index < clients.length; index += 1) {
        const client = clients[index];
        try {
          return await client.chatCompletion(options);
        } catch (error) {
          lastError = error;
          const isLast = index === clients.length - 1;
          if (isLast || !isFailoverEligible(error)) throw error;
        }
      }
      throw lastError instanceof Error ? lastError : new Error('AI provider failed');
    }
  };
}

function getAiProvider(): OpenAICompatibleClient {
  const provider = process.env.AI_PROVIDER || 'alibaba';
  const apiKey = process.env.AI_API_KEY || process.env.ALIBABA_CODING_PLAN_KEY;
  const baseUrl = process.env.AI_BASE_URL || process.env.ALIBABA_BASE_URL || 'https://coding-intl.dashscope.aliyuncs.com/v1';
  const model = process.env.AI_MODEL || process.env.AI_DEFAULT_MODEL || 'qwen3-max-2026-01-23';
  const fallbackModel = process.env.AI_FALLBACK_MODEL || 'qwen3.5-plus';

  if (!apiKey) throw new Error('Missing AI API key. Set AI_API_KEY or ALIBABA_CODING_PLAN_KEY in environment.');

  const clients = [
    createOpenAICompatibleClient({ provider, apiKey, baseUrl, model, timeoutMs: 30000 })
  ];

  // Add fallback client if different model
  if (fallbackModel !== model) {
    clients.push(createOpenAICompatibleClient({ provider, apiKey, baseUrl, model: fallbackModel, timeoutMs: 30000 }));
  }

  return createFailoverClient(clients);
}

// === Guardrails (inline from server/guardrails.ts) ===
type SafetySignal = {
  level: 'none' | 'concern' | 'crisis';
  reason: 'self-harm' | 'abuse' | 'violence' | 'other';
  matched: string[];
};

const SELF_HARM_PATTERNS = [/suicid(e|al)/i, /kill myself/i, /end my life/i, /take my life/i, /self[- ]harm/i, /cut(ting)? myself/i, /overdose/i, /i want to die/i, /can't go on/i, /no reason to live/i];
const ABUSE_PATTERNS = [/abuse(d|r)?/i, /domestic violence/i, /partner hit(s)? me/i, /i was assaulted/i, /sexual assault/i, /rape/i, /molest(ed|ation)/i, /unsafe at home/i];
const VIOLENCE_PATTERNS = [/murder/i, /kill (him|her|them)/i, /shoot/i, /stab/i];

function assessText(text: string): SafetySignal {
  const matched: string[] = [];
  const haystack = text || '';
  for (const pattern of SELF_HARM_PATTERNS) {
    if (pattern.test(haystack)) matched.push(`self-harm: ${pattern.source}`);
  }
  for (const pattern of ABUSE_PATTERNS) {
    if (pattern.test(haystack)) matched.push(`abuse: ${pattern.source}`);
  }
  for (const pattern of VIOLENCE_PATTERNS) {
    if (pattern.test(haystack)) matched.push(`violence: ${pattern.source}`);
  }
  if (matched.length > 0) {
    const reason = matched.some(m => m.startsWith('self-harm')) ? 'self-harm' : matched.some(m => m.startsWith('abuse')) ? 'abuse' : 'violence';
    return { level: 'crisis', reason, matched };
  }
  return { level: 'none', reason: 'other', matched: [] };
}

function extractSafetySignal(texts: (string | undefined | null)[]): SafetySignal {
  const combined = texts.filter(Boolean).join(' ');
  return assessText(combined);
}

function assessOutput(texts: string[]): SafetySignal {
  const combined = texts.filter(Boolean).join(' ');
  for (const pattern of [/how to (kill|harm) yourself/i, /methods? (to|for) suicide/i, /instructions? to self[- ]harm/i]) {
    if (pattern.test(combined)) return { level: 'crisis', reason: 'self-harm', matched: [pattern.source] };
  }
  return { level: 'none', reason: 'other', matched: [] };
}

function buildCrisisDevotion(user: Pick<UserProfile, 'name'>): Devotion {
  const name = user.name || 'Friend';
  return {
    id: randomUUID(),
    date: new Date().toISOString(),
    scriptureReference: 'Psalm 34:18',
    scriptureExcerpt: 'The LORD is near to the brokenhearted and saves the crushed in spirit.',
    scriptureContext: 'In your darkest moment, God is not distant. He draws near to those who are suffering.',
    reflection: `${name}, if you are in crisis, please know that help is available. You are not alone. The pain you feel is real, but it does not have to be the end of your story. Reach out to a trusted friend, family member, or mental health professional. In Singapore, call the Institute of Mental Health helpline at 6389-2222. In the US, call or text 988. Your life matters.`,
    stillnessQuestions: ['Can you take one deep breath with me?', 'Who is one person you could reach out to?', 'What is one small step toward safety you can take now?'],
    how: ['Breathe.', 'Reach out.', 'Stay safe.'],
    prayer: 'God, hold this person close. Bring help, hope, and healing. Amen.'
  };
}

// === Prompts (inline from server/prompts/devotion.ts) ===
const DEVOTION_PROMPT_VERSION = 'v2.0.0';

type PromptBundle = { system: string; user: string };
type DevotionPromptOptions = { avoidScriptureReferences?: string[]; attempt?: number };

function buildDevotionPrompts(user: UserProfile, need: DailyNeed, customContext: string | undefined, options: DevotionPromptOptions = {}): PromptBundle {
  const avoidList = options.avoidScriptureReferences || [];
  const avoidText = avoidList.length > 0 ? `\n\nIMPORTANT: Do NOT use these scripture references (seen in the past 30 days): ${avoidList.join(', ')}. Choose different passages.` : '';

  const systemPrompt = `You are a Christian devotion writer. Write a single daily devotion with this EXACT JSON structure:
{
  "scriptureReference": "Book Chapter:Verse",
  "scriptureExcerpt": "Brief verse excerpt (20-40 words)",
  "scriptureContext": "1-2 sentences of context",
  "reflection": "2-3 paragraphs (~150-250 words)",
  "stillnessQuestions": [3 reflective questions],
  "how": [3 practical actions],
  "prayer": "Short prayer (1-3 sentences)"
}`;

  const userPrompt = `Write today's devotion for someone in ${user.location || 'your area'}.

**Their heart today:** ${need.label || need.type || 'seeking peace'}
${customContext ? `**Additional context:** ${customContext}` : ''}

**About them:**
- Name: ${user.name || 'Friend'}
- Life stage: ${(user.lifeStages || []).join(', ') || 'not specified'}
- Faith background: ${user.faithBackground || 'Christian'}
- Struggles: ${(user.struggles || []).join(', ') || 'not specified'}${avoidText}

**Requirements:**
1. Use ONE primary scripture passage (not from the avoid list)
2. Write in warm, accessible language
3. Include 3 reflective questions for stillness
4. Include 3 practical "how" actions
5. Keep total length under 400 words
6. End with a short prayer

${need.type === 'crisis' || need.type === 'overwhelmed' ? '**Note:** This person may be in distress. Be gentle, hopeful, and practical.' : ''}

Respond ONLY with valid JSON.`;

  return { system: systemPrompt, user: userPrompt };
}

// === Location Index (inline from server/locationIndex.ts) ===
const SINGAPORE_CITIES = ['Singapore', 'Jurong West', 'Woodlands', 'Tampines', 'Sengkang', 'Hougang', 'Choa Chu Kang', 'Yishun', 'Bedok', 'Bukit Batok'];
const MALAYSIA_CITIES = ['Kuala Lumpur', 'Johor Bahru', 'Ipoh', 'Kuching', 'Petaling Jaya', 'Shah Alam', 'George Town', 'Kota Kinabalu', 'Malacca City', 'Seremban'];

function suggestCities(input: string, limit = 5): string[] {
  const query = (input || '').toLowerCase().trim();
  if (!query) return [];
  const allCities = [...SINGAPORE_CITIES, ...MALAYSIA_CITIES];
  const matches = allCities.filter(city => city.toLowerCase().includes(query));
  return matches.slice(0, limit);
}

// === Cache ===
const cityCache = new LRUCache<string, string[]>({ max: 500, ttl: 1000 * 60 * 60 * 12 });
const reverseGeoCache = new LRUCache<string, string>({ max: 500, ttl: 1000 * 60 * 60 * 24 });

// === Helpers ===
function normalizeReference(value: string): string {
  return (value || '').toLowerCase().replace(/\(.*?\)/g, ' ').replace(/[^a-z0-9:]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function buildDevotionFromData(data: Partial<Devotion>): Devotion {
  return {
    id: randomUUID(),
    date: new Date().toISOString(),
    scriptureReference: data.scriptureReference || 'Psalm 46:10',
    scriptureExcerpt: data.scriptureExcerpt || 'Be still, and know that I am God.',
    scriptureContext: data.scriptureContext || 'The Psalmist calls the people of God to recognize His sovereignty.',
    reflection: data.reflection || 'Your struggles are seen by the One who holds the stars.',
    stillnessQuestions: Array.isArray(data.stillnessQuestions) ? data.stillnessQuestions : ['Where is your heart resting?', 'What are you afraid to let go of?', 'Is He enough?'],
    how: Array.isArray(data.how) ? data.how : ['Listen.', 'Reflect.', 'Act.'],
    prayer: data.prayer || 'Father, take this burden from me. Amen.'
  };
}

function parseJsonObject<T>(input: string, fallback: T): T {
  const direct = safeParseJson<T>(input);
  if (direct) return direct;
  const trimmed = input.trim();
  const start = trimmed.indexOf('{');
  const end = trimmed.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    const candidate = trimmed.slice(start, end + 1);
    const parsed = safeParseJson<T>(candidate);
    if (parsed) return parsed;
  }
  return fallback;
}

function safeParseJson<T>(input: string): T | null {
  try { return JSON.parse(input) as T; } catch { return null; }
}

async function generateDevotion(user: UserProfile, need: DailyNeed, customContext: string | undefined, options?: { avoidScriptureReferences?: string[] }): Promise<Devotion> {
  const avoidList = (options?.avoidScriptureReferences || []).map(normalizeReference).filter(Boolean);
  const avoidSet = new Set(avoidList);
  const attempts = avoidSet.size > 0 ? 2 : 1;
  let last: Partial<Devotion> = {};

  for (let attempt = 0; attempt < attempts; attempt += 1) {
    const prompts = buildDevotionPrompts(user, need, customContext, { avoidScriptureReferences: options?.avoidScriptureReferences, attempt });
    const provider = getAiProvider();
    const response = await provider.chatCompletion({ system: prompts.system, user: prompts.user, temperature: 0.4, maxTokens: 1200 });
    const data = parseJsonObject<Partial<Devotion>>(response, {});
    last = data;
    if (!avoidSet.size) return buildDevotionFromData(data);
    const reference = normalizeReference(data.scriptureReference || '');
    if (reference && !avoidSet.has(reference)) return buildDevotionFromData(data);
  }
  return buildDevotionFromData(last);
}

async function generateCitySuggestions(input: string): Promise<string[]> {
  const key = input.trim().toLowerCase();
  const cached = cityCache.get(key);
  if (cached) return cached;
  const suggestions = suggestCities(input, 5);
  cityCache.set(key, suggestions);
  return suggestions;
}

async function reverseGeocode(latitude: number, longitude: number): Promise<string> {
  const key = `${latitude.toFixed(4)},${longitude.toFixed(4)}`;
  const cached = reverseGeoCache.get(key);
  if (cached) return cached;
  // Simple reverse geocoding based on coordinates
  const isSingapore = latitude >= 1.1 && latitude <= 1.5 && longitude >= 103.6 && longitude <= 104.1;
  const city = isSingapore ? 'Singapore' : 'Malaysia';
  reverseGeoCache.set(key, city);
  return city;
}

// === Vercel API Handler ===
export default async function handler(req: VercelRequest, res: VercelResponse) {
  const allowedOrigins = (process.env.CORS_ORIGIN || 'http://localhost:3000,http://localhost:5173,http://localhost:5174,http://localhost:5175,capacitor://localhost,https://stillness-daily-devotion.vercel.app').split(',');
  const origin = req.headers.origin || '';
  if (allowedOrigins.includes(origin) || !origin) res.setHeader('Access-Control-Allow-Origin', origin || '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') return res.status(200).end();

  const url = new URL(req.url || '', 'http://localhost');
  const pathname = url.pathname;

  try {
    // POST /api/devotion
    if (req.method === 'POST' && pathname === '/api/devotion') {
      const { user, need, customContext, avoidScriptureReferences } = req.body;
      if (!user || !need) return res.status(400).json({ error: 'Missing user or need.' });

      const safetySignal = extractSafetySignal([user.name, user.location, user.struggles?.join(' '), customContext]);
      if (safetySignal.level !== 'none') {
        const safeDevotion = buildCrisisDevotion({ name: user.name });
        return res.json({ ...safeDevotion, safety: safetySignal });
      }

      const devotion = await generateDevotion(user, need, customContext, { avoidScriptureReferences });
      const outputAssessment = assessOutput([devotion.scriptureReference, devotion.reflection]);
      return res.json({ ...devotion, safety: outputAssessment });
    }

    // POST /api/city-suggestions
    if (req.method === 'POST' && pathname === '/api/city-suggestions') {
      const { input } = req.body;
      const suggestions = await generateCitySuggestions(input);
      return res.json(suggestions);
    }

    // POST /api/geo-to-city
    if (req.method === 'POST' && pathname === '/api/geo-to-city') {
      const { latitude, longitude } = req.body;
      const city = await reverseGeocode(latitude, longitude);
      return res.json({ city });
    }

    return res.status(404).json({ error: 'Not found' });
  } catch (error) {
    console.error('API error:', error);
    return res.status(500).json({ error: error instanceof Error ? error.message : 'Internal server error' });
  }
}

